const input = $input.first().json;
const body = input.body || input.query || {};
const { nombre, apellido, whatsapp, email, telefono, lead_tipo, origen, categoria, nivel, objetivo, resumen, disponibilidad, tags, primer_contacto } = body;

if (!nombre || !whatsapp) {
  throw new Error('Faltan campos requeridos: nombre, whatsapp');
}

const nom = String(nombre).replace(/'/g, "''");
const ap = apellido ? String(apellido).replace(/'/g, "''") : null;
const res = resumen ? String(resumen).replace(/'/g, "''") : null;
const obj = objetivo ? String(objetivo).replace(/'/g, "''") : null;
const dis = disponibilidad ? String(disponibilidad).replace(/'/g, "''") : null;

const query = `INSERT INTO leads (nombre, apellido, whatsapp, email, telefono, lead_tipo, origen, categoria, nivel, objetivo, resumen, disponibilidad, tags, estado, estado_motivo, estado_fecha, primer_contacto, ultimo_contacto, created_at, updated_at)
VALUES ('${nom}', ${ap ? `'${ap}'` : 'null'}, '${whatsapp}', ${email ? `'${email}'` : 'null'}, ${telefono ? `'${telefono}'` : 'null'}, ${lead_tipo ? `'${lead_tipo}'` : 'null'}, ${origen ? `'${origen}'` : 'null'}, ${categoria ? `'${categoria}'` : 'null'}, ${nivel ? `'${nivel}'` : 'null'}, ${obj ? `'${obj}'` : 'null'}, ${res ? `'${res}'` : 'null'}, ${dis ? `'${dis}'` : 'null'}, ${tags ? `'${tags}'` : 'null'}, 'NUEVO', 'Nuevo contacto', CURRENT_TIMESTAMP, ${primer_contacto ? `'${primer_contacto}'` : 'CURRENT_TIMESTAMP'}, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP)
RETURNING id, nombre, whatsapp, email, lead_tipo, origen, nivel, estado, created_at;`;

return [{json: {query}}];
